import { useState, useRef, useEffect, useCallback } from 'react';
import * as THREE from 'three';
import {
  Type, Upload, ImageIcon, RotateCcw, ShoppingCart, Check,
  Bold, Italic, AlignLeft, AlignCenter, AlignRight,
  Trash2, Copy, MoveUp, MoveDown, ZoomIn, ZoomOut,
  ChevronDown, ChevronRight, Layers, Sparkles, Download,
  RotateCw, FlipHorizontal, Minus, Plus,
} from 'lucide-react';
import { useCart } from '../context/AppContext';
import { MOCK_PRODUCTS, FIGMA_ASSETS, ASSETS } from '../utils/constants';

// ── Constantes ────────────────────────────────────────────────────────────────
const PRODUCTS_3D = [
  { id: 1, name: 'T-Shirt',   color: '#E5A6A8', printArea: { x: 0.28, y: 0.22, w: 0.44, h: 0.40 }, price: 10000 },
  { id: 2, name: 'Sweat',     color: '#02AB84', printArea: { x: 0.27, y: 0.20, w: 0.46, h: 0.42 }, price: 15000 },
  { id: 3, name: 'Hoodie',    color: '#6366F1', printArea: { x: 0.28, y: 0.22, w: 0.44, h: 0.38 }, price: 18000 },
  { id: 4, name: 'Mug',       color: '#E6B95E', printArea: { x: 0.20, y: 0.25, w: 0.60, h: 0.50 }, price: 8000  },
  { id: 5, name: 'Sneakers',  color: '#017BFE', printArea: { x: 0.15, y: 0.30, w: 0.70, h: 0.40 }, price: 25000 },
  { id: 6, name: 'Casquette', color: '#232323', printArea: { x: 0.25, y: 0.15, w: 0.50, h: 0.45 }, price: 7000  },
];

const PRODUCT_IMGS = {
  1: FIGMA_ASSETS.tshirt1,
  2: FIGMA_ASSETS.sweater,
  3: FIGMA_ASSETS.hoodie,
  4: FIGMA_ASSETS.mug,
  5: FIGMA_ASSETS.sneaker,
  6: FIGMA_ASSETS.product2,
};

const FONTS = [
  'Poppins', 'Georgia', 'Impact', 'Courier New',
  'Arial Black', 'Trebuchet MS', 'Comic Sans MS',
];

const PALETTE = [
  '#000000','#FFFFFF','#017BFE','#00C2FF',
  '#02AB84','#E6B95E','#E5A6A8','#EF4444',
  '#8B5CF6','#EC4899','#F97316','#14B8A6',
];

const PRODUCT_COLORS = [
  '#FFFFFF','#000000','#1E293B','#017BFE',
  '#E5A6A8','#02AB84','#E6B95E','#EF4444',
  '#8B5CF6','#F4F4F4','#78716C','#6366F1',
];

const STICKER_LIBRARY = [
  { cat: 'Otaku',      items: ['⚔️','🗡️','🌸','🎌','🐉','💮','⛩️','🌙','🔥','💫'] },
  { cat: 'Nature',     items: ['🌿','🌺','🍃','🌊','🌴','🦋','🌸','🍀','🌻','🦅'] },
  { cat: 'Gaming',     items: ['🎮','👾','🕹️','🃏','♟️','🎯','🏆','⚡','💎','🔮'] },
  { cat: 'Motivation', items: ['💪','🔥','⚡','🚀','🏆','✨','🌟','👑','🎯','💯'] },
  { cat: 'Sport',      items: ['⚽','🏀','🎾','🏈','⚾','🥊','🏊','🚴','🧘','🏋️'] },
  { cat: 'Formes',     items: ['⭐','❤️','💙','🔷','🔶','⬡','◆','▲','●','✦'] },
];

const SIZES = ['XS','S','M','L','XL','XXL'];

// ── Utilitaires ───────────────────────────────────────────────────────────────
const uid = () => Math.random().toString(36).slice(2, 9);

// ── Viewer 3D Three.js ────────────────────────────────────────────────────────
function Viewer3D({ productColor, canvasTexture }) {
  const mountRef = useRef(null);
  const sceneRef = useRef({});

  useEffect(() => {
    const mount = mountRef.current;
    if (!mount) return;
    const W = mount.clientWidth, H = mount.clientHeight;

    // Renderer
    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(W, H);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    mount.appendChild(renderer.domElement);

    // Scene & Camera
    const scene  = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(45, W / H, 0.1, 100);
    camera.position.set(0, 0, 3.2);

    // Lumières
    const ambient  = new THREE.AmbientLight(0xffffff, 0.8);
    const dirLight = new THREE.DirectionalLight(0xffffff, 1.2);
    dirLight.position.set(3, 5, 5);
    dirLight.castShadow = true;
    const rimLight = new THREE.DirectionalLight(0x6699ff, 0.4);
    rimLight.position.set(-3, -2, -3);
    scene.add(ambient, dirLight, rimLight);

    // Géométrie — torso simplifié (corps du t-shirt)
    const shape = new THREE.Shape();
    shape.moveTo(-0.7, -1.1);
    shape.lineTo(-0.7,  0.6);
    shape.lineTo(-1.1,  0.85);
    shape.lineTo(-0.85, 1.1);
    shape.lineTo(-0.55, 0.85);
    shape.lineTo(-0.55, 0.95);
    shape.lineTo( 0.55, 0.95);
    shape.lineTo( 0.55, 0.85);
    shape.lineTo( 0.85, 1.1);
    shape.lineTo( 1.1,  0.85);
    shape.lineTo( 0.7,  0.6);
    shape.lineTo( 0.7, -1.1);
    shape.closePath();

    const extrudeSettings = { depth: 0.12, bevelEnabled: true, bevelSize: 0.03, bevelThickness: 0.03, bevelSegments: 4 };
    const geo = new THREE.ExtrudeGeometry(shape, extrudeSettings);

    // Texture couleur + design
    const texCanvas = document.createElement('canvas');
    texCanvas.width  = 512;
    texCanvas.height = 512;
    const ctx = texCanvas.getContext('2d');

    // Fond couleur
    ctx.fillStyle = productColor;
    ctx.fillRect(0, 0, 512, 512);

    // Léger gradient pour donner du volume
    const grad = ctx.createRadialGradient(256, 180, 30, 256, 256, 320);
    grad.addColorStop(0, 'rgba(255,255,255,0.12)');
    grad.addColorStop(1, 'rgba(0,0,0,0.08)');
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, 512, 512);

    // Zone d'impression (si canvasTexture fourni)
    if (canvasTexture) {
      ctx.drawImage(canvasTexture, 140, 160, 230, 200);
    }

    const tex = new THREE.CanvasTexture(texCanvas);
    const mat = new THREE.MeshStandardMaterial({
      map: tex, roughness: 0.65, metalness: 0.05,
      side: THREE.DoubleSide,
    });

    const mesh = new THREE.Mesh(geo, mat);
    mesh.castShadow = true;
    scene.add(mesh);
    sceneRef.current.mesh = mesh;
    sceneRef.current.tex  = tex;
    sceneRef.current.ctx  = ctx;
    sceneRef.current.texCanvas = texCanvas;

    // Rotation auto + drag
    let isDragging = false, prevX = 0, prevY = 0;
    let rotY = 0, rotX = 0, autoRot = true;

    const onDown  = (e) => { isDragging = true; autoRot = false; prevX = e.clientX || e.touches?.[0]?.clientX; prevY = e.clientY || e.touches?.[0]?.clientY; };
    const onUp    = () => { isDragging = false; };
    const onMove  = (e) => {
      if (!isDragging) return;
      const cx = e.clientX || e.touches?.[0]?.clientX;
      const cy = e.clientY || e.touches?.[0]?.clientY;
      rotY += (cx - prevX) * 0.012;
      rotX += (cy - prevY) * 0.008;
      rotX  = Math.max(-0.5, Math.min(0.5, rotX));
      prevX = cx; prevY = cy;
    };

    renderer.domElement.addEventListener('mousedown',  onDown);
    renderer.domElement.addEventListener('touchstart', onDown,  { passive: true });
    window.addEventListener('mouseup',   onUp);
    window.addEventListener('touchend',  onUp);
    window.addEventListener('mousemove', onMove);
    window.addEventListener('touchmove', onMove, { passive: true });

    // Boucle de rendu
    let frame;
    const animate = () => {
      frame = requestAnimationFrame(animate);
      if (autoRot) rotY += 0.005;
      mesh.rotation.y = rotY;
      mesh.rotation.x = rotX;
      renderer.render(scene, camera);
    };
    animate();

    sceneRef.current.renderer = renderer;
    sceneRef.current.cleanup  = () => {
      cancelAnimationFrame(frame);
      renderer.domElement.removeEventListener('mousedown',  onDown);
      renderer.domElement.removeEventListener('touchstart', onDown);
      window.removeEventListener('mouseup',   onUp);
      window.removeEventListener('touchend',  onUp);
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('touchmove', onMove);
      renderer.dispose();
      if (mount.contains(renderer.domElement)) mount.removeChild(renderer.domElement);
    };

    return () => sceneRef.current.cleanup?.();
  }, []);

  // Mettre à jour la couleur / texture sans tout recréer
  useEffect(() => {
    const { ctx, texCanvas, tex, mesh } = sceneRef.current;
    if (!ctx || !texCanvas || !tex) return;
    ctx.fillStyle = productColor;
    ctx.fillRect(0, 0, 512, 512);
    const grad = ctx.createRadialGradient(256, 180, 30, 256, 256, 320);
    grad.addColorStop(0, 'rgba(255,255,255,0.12)');
    grad.addColorStop(1, 'rgba(0,0,0,0.08)');
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, 512, 512);
    if (canvasTexture) ctx.drawImage(canvasTexture, 140, 160, 230, 200);
    tex.needsUpdate = true;
  }, [productColor, canvasTexture]);

  return (
    <div
      ref={mountRef}
      style={{ width: '100%', height: '100%', cursor: 'grab' }}
      title="Faites glisser pour faire pivoter"
    />
  );
}

// ── Éditeur canvas 2D (zone de design) ───────────────────────────────────────
function DesignCanvas({ elements, selectedId, onSelect, onUpdate, productImg, productColor }) {
  const canvasRef   = useRef(null);
  const [drag, setDrag] = useState(null); // { id, startX, startY, origX, origY }

  const handleMouseDown = (e, id) => {
    e.stopPropagation();
    onSelect(id);
    const rect = canvasRef.current.getBoundingClientRect();
    const el   = elements.find(el => el.id === id);
    setDrag({ id, startX: e.clientX, startY: e.clientY, origX: el.x, origY: el.y });
  };

  const handleMouseMove = useCallback((e) => {
    if (!drag) return;
    const dx = e.clientX - drag.startX;
    const dy = e.clientY - drag.startY;
    onUpdate(drag.id, { x: drag.origX + dx, y: drag.origY + dy });
  }, [drag, onUpdate]);

  const handleMouseUp = useCallback(() => setDrag(null), []);

  useEffect(() => {
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup',   handleMouseUp);
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup',   handleMouseUp);
    };
  }, [handleMouseMove, handleMouseUp]);

  return (
    <div
      ref={canvasRef}
      onClick={() => onSelect(null)}
      style={{
        width: '100%', height: '100%',
        position: 'relative',
        userSelect: 'none',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        background: 'repeating-conic-gradient(#f0f0f0 0% 25%, white 0% 50%) 0 0 / 20px 20px',
      }}
    >
      {/* Produit (maquette) */}
      <div style={{
        position: 'relative', width: 320, height: 380,
        borderRadius: 20, overflow: 'visible',
        filter: 'drop-shadow(0 16px 48px rgba(0,0,0,0.18))',
      }}>
        {/* Fond coloré */}
        <div style={{
          position: 'absolute', inset: 0, borderRadius: 20,
          background: productColor,
          transition: 'background 0.3s',
        }} />

        {/* Image produit */}
        <img
          src={productImg}
          alt=""
          style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', objectFit: 'contain', borderRadius: 20 }}
          onError={e => e.target.style.opacity = '0'}
          draggable={false}
        />

        {/* Zone d'impression visuelle */}
        <div style={{
          position: 'absolute', top: '22%', left: '28%', right: '28%', bottom: '35%',
          border: '1.5px dashed rgba(1,123,254,0.35)',
          borderRadius: 8, pointerEvents: 'none',
        }} />

        {/* Éléments de design */}
        {elements.map(el => (
          <div
            key={el.id}
            onMouseDown={e => handleMouseDown(e, el.id)}
            style={{
              position: 'absolute',
              left: el.x, top: el.y,
              cursor: 'move',
              outline: selectedId === el.id ? '2px solid #017BFE' : 'none',
              outlineOffset: 3,
              borderRadius: 4,
              zIndex: el.zIndex || 2,
              transform: `rotate(${el.rotation || 0}deg) scaleX(${el.flipX ? -1 : 1})`,
              transformOrigin: 'center center',
            }}
          >
            {el.type === 'text' && (
              <p style={{
                fontFamily: el.font || 'Poppins',
                fontSize: el.size || 20,
                color: el.color || '#000',
                fontWeight: el.bold ? 800 : 600,
                fontStyle: el.italic ? 'italic' : 'normal',
                textAlign: el.align || 'center',
                whiteSpace: 'nowrap',
                margin: 0,
                lineHeight: 1.2,
                textShadow: el.color === '#FFFFFF' ? '0 1px 3px rgba(0,0,0,0.4)' : 'none',
              }}>
                {el.text}
              </p>
            )}
            {el.type === 'sticker' && (
              <span style={{ fontSize: el.size || 36, lineHeight: 1, display: 'block' }}>{el.emoji}</span>
            )}
            {el.type === 'image' && (
              <img src={el.src} alt="" style={{ width: el.size || 80, height: el.size || 80, objectFit: 'contain' }} draggable={false} />
            )}
            {/* Poignée de sélection */}
            {selectedId === el.id && (
              <div style={{
                position: 'absolute', bottom: -6, right: -6,
                width: 12, height: 12, borderRadius: '50%',
                background: '#017BFE', border: '2px solid white',
                cursor: 'se-resize', zIndex: 10,
              }} />
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════════
// PAGE PRINCIPALE
// ════════════════════════════════════════════════════════════════════════════════
export default function Personnalisation() {
  const { addItem } = useCart();

  // ── État produit ──────────────────────────────────────────────────────────
  const [selectedProduct, setSelectedProduct] = useState(PRODUCTS_3D[0]);
  const [productColor,    setProductColor]    = useState(PRODUCTS_3D[0].color);
  const [selectedSize,    setSelectedSize]    = useState('M');
  const [view3D,          setView3D]          = useState(false);

  // ── État design ───────────────────────────────────────────────────────────
  const [elements,    setElements]    = useState([]);
  const [selectedId,  setSelectedId]  = useState(null);
  const [activeTool,  setActiveTool]  = useState('text');
  const [stickerCat,  setStickerCat]  = useState(0);

  // ── État texte ────────────────────────────────────────────────────────────
  const [text,      setText]      = useState('Mon texte');
  const [font,      setFont]      = useState('Poppins');
  const [fontSize,  setFontSize]  = useState(22);
  const [textColor, setTextColor] = useState('#000000');
  const [bold,      setBold]      = useState(false);
  const [italic,    setItalic]    = useState(false);
  const [align,     setAlign]     = useState('center');

  // ── État UI ───────────────────────────────────────────────────────────────
  const [added,       setAdded]       = useState(false);
  const [leftOpen,    setLeftOpen]    = useState(true);
  const [rightOpen,   setRightOpen]   = useState(true);
  const fileRef = useRef();

  const selectedEl = elements.find(el => el.id === selectedId);

  // ── Helpers éléments ──────────────────────────────────────────────────────
  const addText = () => {
    const el = { id: uid(), type: 'text', text, font, size: fontSize, color: textColor, bold, italic, align, x: 100, y: 100, zIndex: elements.length + 2 };
    setElements(prev => [...prev, el]);
    setSelectedId(el.id);
  };

  const addSticker = (emoji) => {
    const el = { id: uid(), type: 'sticker', emoji, size: 40, x: 110, y: 110, zIndex: elements.length + 2 };
    setElements(prev => [...prev, el]);
    setSelectedId(el.id);
  };

  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = ev => {
      const el = { id: uid(), type: 'image', src: ev.target.result, size: 90, x: 100, y: 100, zIndex: elements.length + 2 };
      setElements(prev => [...prev, el]);
      setSelectedId(el.id);
    };
    reader.readAsDataURL(file);
  };

  const updateElement = useCallback((id, patch) => {
    setElements(prev => prev.map(el => el.id === id ? { ...el, ...patch } : el));
  }, []);

  const deleteElement = (id) => {
    setElements(prev => prev.filter(el => el.id !== id));
    setSelectedId(null);
  };

  const duplicateElement = (id) => {
    const el = elements.find(e => e.id === id);
    if (!el) return;
    const copy = { ...el, id: uid(), x: el.x + 16, y: el.y + 16 };
    setElements(prev => [...prev, copy]);
    setSelectedId(copy.id);
  };

  const resetAll = () => { setElements([]); setSelectedId(null); };

  const handleAddToCart = () => {
    addItem({ ...MOCK_PRODUCTS[0], name: `${selectedProduct.name} Personnalisé`, id: Date.now(), price: selectedProduct.price });
    setAdded(true);
    setTimeout(() => setAdded(false), 2000);
  };

  // ── Sync texte avec élément sélectionné ──────────────────────────────────
  useEffect(() => {
    if (selectedEl?.type === 'text') {
      updateElement(selectedId, { text, font, size: fontSize, color: textColor, bold, italic, align });
    }
  }, [text, font, fontSize, textColor, bold, italic, align]);

  // ── Styles communs ────────────────────────────────────────────────────────
  const panel = {
    background: 'white', borderRadius: 16,
    boxShadow: '0 2px 16px rgba(0,0,0,0.07)',
    border: '1px solid #F0F0F0',
    overflow: 'hidden',
  };

  const sectionTitle = (label, icon) => (
    <div style={{ padding: '14px 16px', borderBottom: '1px solid #F5F5F5', display: 'flex', alignItems: 'center', gap: 8 }}>
      {icon}
      <span style={{ fontSize: 13, fontWeight: 700, color: '#0D0D0D' }}>{label}</span>
    </div>
  );

  const toolBtn = (id, Icon, label) => (
    <button
      key={id}
      onClick={() => setActiveTool(id)}
      style={{
        flex: 1, padding: '10px 4px',
        border: `1.5px solid ${activeTool === id ? '#017BFE' : '#EBEBEB'}`,
        borderRadius: 10,
        background: activeTool === id ? 'rgba(1,123,254,0.07)' : 'white',
        color: activeTool === id ? '#017BFE' : '#555',
        cursor: 'pointer',
        display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 5,
        fontSize: 11, fontWeight: 700,
        transition: 'all 0.2s',
        fontFamily: 'Poppins, sans-serif',
      }}
    >
      <Icon size={16} />
      {label}
    </button>
  );

  return (
    <div style={{ background: '#F7F8FA', minHeight: '100vh' }}>

      {/* ── Header ─────────────────────────────────────────────────────────── */}
      <div style={{
        background: 'white', borderBottom: '1px solid #EBEBEB',
        padding: '14px 24px',
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        position: 'sticky', top: 70, zIndex: 40,
      }}>
        <div>
          <h1 style={{ fontSize: 18, fontWeight: 800, color: '#0D0D0D', marginBottom: 2 }}>
            Éditeur de design
          </h1>
          <p style={{ fontSize: 12, color: '#888' }}>
            {selectedProduct.name} · {selectedSize} · {productColor.toUpperCase()}
          </p>
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          {/* Toggle 2D / 3D */}
          <button
            onClick={() => setView3D(v => !v)}
            style={{
              display: 'flex', alignItems: 'center', gap: 6,
              padding: '8px 16px', borderRadius: 10,
              border: '1.5px solid #EBEBEB',
              background: view3D ? '#0D0D0D' : 'white',
              color: view3D ? 'white' : '#555',
              fontWeight: 700, fontSize: 12, cursor: 'pointer',
              fontFamily: 'Poppins, sans-serif',
              transition: 'all 0.25s',
            }}
          >
            <Layers size={14} />
            {view3D ? 'Vue 2D' : 'Vue 3D'}
          </button>

          <button
            onClick={resetAll}
            style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '8px 16px', borderRadius: 10, border: '1.5px solid #EBEBEB', background: 'white', color: '#555', fontWeight: 700, fontSize: 12, cursor: 'pointer', fontFamily: 'Poppins, sans-serif' }}
          >
            <RotateCcw size={14} /> Réinitialiser
          </button>

          <button
            onClick={handleAddToCart}
            style={{
              display: 'flex', alignItems: 'center', gap: 8,
              padding: '10px 22px', borderRadius: 10,
              background: added ? '#02AB84' : 'linear-gradient(135deg, #017BFE, #00C2FF)',
              color: 'white', border: 'none',
              fontWeight: 700, fontSize: 13, cursor: 'pointer',
              fontFamily: 'Poppins, sans-serif',
              transition: 'background 0.3s',
              boxShadow: '0 4px 12px rgba(1,123,254,0.3)',
            }}
          >
            {added ? <><Check size={15} /> Ajouté</> : <><ShoppingCart size={15} /> Ajouter au panier · {selectedProduct.price.toLocaleString('fr-FR')} FCFA</>}
          </button>
        </div>
      </div>

      {/* ── Layout 3 colonnes ──────────────────────────────────────────────── */}
      <div style={{
        maxWidth: 1400, margin: '0 auto', padding: '20px 16px',
        display: 'grid',
        gridTemplateColumns: `${leftOpen ? '280px' : '40px'} 1fr ${rightOpen ? '280px' : '40px'}`,
        gap: 16,
        transition: 'grid-template-columns 0.3s var(--ease-smooth)',
        minHeight: 'calc(100vh - 140px)',
      }}>

        {/* ════════ PANNEAU GAUCHE ════════ */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>

          {/* Toggle */}
          <button
            onClick={() => setLeftOpen(v => !v)}
            style={{ alignSelf: 'flex-end', background: 'white', border: '1px solid #EBEBEB', borderRadius: 8, padding: '6px 8px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 4, fontSize: 11, color: '#666', fontFamily: 'Poppins, sans-serif' }}
          >
            {leftOpen ? <><ChevronDown size={12} /> Réduire</> : <ChevronRight size={12} />}
          </button>

          {leftOpen && <>
            {/* Produit */}
            <div style={panel}>
              {sectionTitle('Choisir le produit', <ImageIcon size={14} color="#017BFE" />)}
              <div style={{ padding: 12, display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
                {PRODUCTS_3D.map(p => (
                  <button
                    key={p.id}
                    onClick={() => { setSelectedProduct(p); setProductColor(p.color); }}
                    style={{
                      border: `2px solid ${selectedProduct.id === p.id ? '#017BFE' : '#EBEBEB'}`,
                      borderRadius: 10, padding: '10px 8px',
                      background: selectedProduct.id === p.id ? 'rgba(1,123,254,0.06)' : 'white',
                      cursor: 'pointer', textAlign: 'center',
                      transition: 'all 0.2s',
                      fontFamily: 'Poppins, sans-serif',
                    }}
                  >
                    <img
                      src={PRODUCT_IMGS[p.id]}
                      alt={p.name}
                      style={{ height: 52, objectFit: 'contain', display: 'block', margin: '0 auto 4px' }}
                      onError={e => e.target.style.display = 'none'}
                    />
                    <span style={{ fontSize: 11, fontWeight: 700, color: selectedProduct.id === p.id ? '#017BFE' : '#555' }}>
                      {p.name}
                    </span>
                    <br />
                    <span style={{ fontSize: 10, color: '#888' }}>{p.price.toLocaleString('fr-FR')} F</span>
                  </button>
                ))}
              </div>
            </div>

            {/* Outils */}
            <div style={panel}>
              {sectionTitle('Outils de design', <Sparkles size={14} color="#017BFE" />)}
              <div style={{ padding: 12 }}>
                <div style={{ display: 'flex', gap: 8, marginBottom: 14 }}>
                  {toolBtn('text',    Type,      'Texte')}
                  {toolBtn('sticker', Sparkles,  'Sticker')}
                  {toolBtn('image',   Upload,    'Image')}
                </div>

                {/* ── Outil Texte ── */}
                {activeTool === 'text' && (
                  <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
                    <div>
                      <label style={{ fontSize: 11, fontWeight: 700, display: 'block', marginBottom: 5, color: '#555', textTransform: 'uppercase', letterSpacing: '0.05em' }}>Contenu</label>
                      <textarea
                        value={text}
                        onChange={e => setText(e.target.value)}
                        rows={2}
                        style={{ width: '100%', border: '1.5px solid #EBEBEB', borderRadius: 8, padding: '8px 10px', fontSize: 13, outline: 'none', fontFamily: font, resize: 'none' }}
                      />
                    </div>

                    <div>
                      <label style={{ fontSize: 11, fontWeight: 700, display: 'block', marginBottom: 5, color: '#555', textTransform: 'uppercase', letterSpacing: '0.05em' }}>Police</label>
                      <select value={font} onChange={e => setFont(e.target.value)} style={{ width: '100%', border: '1.5px solid #EBEBEB', borderRadius: 8, padding: '7px 10px', fontSize: 12, outline: 'none', fontFamily: 'Poppins, sans-serif' }}>
                        {FONTS.map(f => <option key={f} value={f}>{f}</option>)}
                      </select>
                    </div>

                    <div>
                      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 5 }}>
                        <label style={{ fontSize: 11, fontWeight: 700, color: '#555', textTransform: 'uppercase', letterSpacing: '0.05em' }}>Taille</label>
                        <span style={{ fontSize: 12, fontWeight: 700, color: '#017BFE' }}>{fontSize}px</span>
                      </div>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                        <button onClick={() => setFontSize(s => Math.max(10, s - 2))} style={{ width: 28, height: 28, borderRadius: '50%', border: '1px solid #EBEBEB', background: 'white', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><Minus size={12} /></button>
                        <input type="range" min={10} max={80} value={fontSize} onChange={e => setFontSize(Number(e.target.value))} style={{ flex: 1, accentColor: '#017BFE' }} />
                        <button onClick={() => setFontSize(s => Math.min(80, s + 2))} style={{ width: 28, height: 28, borderRadius: '50%', border: '1px solid #EBEBEB', background: 'white', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><Plus size={12} /></button>
                      </div>
                    </div>

                    {/* Style */}
                    <div style={{ display: 'flex', gap: 6 }}>
                      {[
                        { icon: Bold,        active: bold,   toggle: () => setBold(v => !v),   label: 'Gras' },
                        { icon: Italic,      active: italic, toggle: () => setItalic(v => !v), label: 'Italique' },
                        { icon: AlignLeft,   active: align === 'left',   toggle: () => setAlign('left'),   label: 'Gauche' },
                        { icon: AlignCenter, active: align === 'center', toggle: () => setAlign('center'), label: 'Centre' },
                        { icon: AlignRight,  active: align === 'right',  toggle: () => setAlign('right'),  label: 'Droite' },
                      ].map(({ icon: Icon, active, toggle, label }) => (
                        <button
                          key={label}
                          onClick={toggle}
                          title={label}
                          style={{
                            flex: 1, height: 32, border: `1.5px solid ${active ? '#017BFE' : '#EBEBEB'}`,
                            borderRadius: 7, background: active ? 'rgba(1,123,254,0.08)' : 'white',
                            cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center',
                            transition: 'all 0.15s',
                          }}
                        >
                          <Icon size={13} color={active ? '#017BFE' : '#555'} />
                        </button>
                      ))}
                    </div>

                    {/* Couleur texte */}
                    <div>
                      <label style={{ fontSize: 11, fontWeight: 700, display: 'block', marginBottom: 6, color: '#555', textTransform: 'uppercase', letterSpacing: '0.05em' }}>Couleur</label>
                      <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
                        {PALETTE.map(c => (
                          <button
                            key={c}
                            onClick={() => setTextColor(c)}
                            style={{
                              width: 26, height: 26, borderRadius: '50%',
                              background: c, border: textColor === c ? '2.5px solid #017BFE' : '2px solid #EBEBEB',
                              cursor: 'pointer', padding: 0,
                              transform: textColor === c ? 'scale(1.25)' : 'scale(1)',
                              transition: 'transform 0.15s, border 0.15s',
                              boxShadow: c === '#FFFFFF' ? 'inset 0 0 0 1px #ccc' : 'none',
                            }}
                          />
                        ))}
                      </div>
                    </div>

                    <button
                      onClick={addText}
                      style={{
                        width: '100%', padding: '10px', borderRadius: 10,
                        background: 'linear-gradient(135deg, #017BFE, #00C2FF)',
                        color: 'white', border: 'none', fontWeight: 700, fontSize: 13,
                        cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6,
                        fontFamily: 'Poppins, sans-serif',
                      }}
                    >
                      <Type size={14} /> Ajouter le texte
                    </button>
                  </div>
                )}

                {/* ── Outil Stickers ── */}
                {activeTool === 'sticker' && (
                  <div>
                    {/* Catégories */}
                    <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap', marginBottom: 10 }}>
                      {STICKER_LIBRARY.map((cat, i) => (
                        <button
                          key={cat.cat}
                          onClick={() => setStickerCat(i)}
                          style={{
                            padding: '4px 10px', borderRadius: 20, border: 'none',
                            background: stickerCat === i ? '#0D0D0D' : '#F4F4F4',
                            color: stickerCat === i ? 'white' : '#555',
                            fontSize: 11, fontWeight: 700, cursor: 'pointer',
                            fontFamily: 'Poppins, sans-serif',
                          }}
                        >
                          {cat.cat}
                        </button>
                      ))}
                    </div>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: 6 }}>
                      {STICKER_LIBRARY[stickerCat].items.map((emoji, i) => (
                        <button
                          key={i}
                          onClick={() => addSticker(emoji)}
                          style={{
                            fontSize: 24, padding: '8px 4px', border: '1.5px solid #EBEBEB',
                            borderRadius: 8, background: 'white', cursor: 'pointer',
                            transition: 'transform 0.15s, border-color 0.15s',
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                          }}
                          onMouseEnter={e => { e.currentTarget.style.transform = 'scale(1.2)'; e.currentTarget.style.borderColor = '#017BFE'; }}
                          onMouseLeave={e => { e.currentTarget.style.transform = 'scale(1)';   e.currentTarget.style.borderColor = '#EBEBEB'; }}
                        >
                          {emoji}
                        </button>
                      ))}
                    </div>
                  </div>
                )}

                {/* ── Outil Image ── */}
                {activeTool === 'image' && (
                  <div>
                    <input ref={fileRef} type="file" accept="image/*" onChange={handleImageUpload} style={{ display: 'none' }} />
                    <button
                      onClick={() => fileRef.current.click()}
                      style={{
                        width: '100%', border: '2px dashed #017BFE',
                        borderRadius: 10, padding: '22px 16px',
                        background: 'rgba(1,123,254,0.03)', cursor: 'pointer',
                        display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 8, color: '#017BFE',
                      }}
                    >
                      <Upload size={22} />
                      <span style={{ fontSize: 13, fontWeight: 700, fontFamily: 'Poppins, sans-serif' }}>Importer votre design</span>
                      <span style={{ fontSize: 11, color: '#888', fontFamily: 'Poppins, sans-serif' }}>PNG, JPG, SVG — max 5 MB</span>
                    </button>

                    <p style={{ fontSize: 11, color: '#aaa', marginTop: 10, lineHeight: 1.6, fontFamily: 'Poppins, sans-serif' }}>
                      Conseil : utilisez des fichiers PNG avec fond transparent pour un résultat optimal.
                    </p>
                  </div>
                )}
              </div>
            </div>
          </>}
        </div>

        {/* ════════ CANVAS CENTRAL ════════ */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>

          {/* Barre d'actions élément sélectionné */}
          {selectedEl && (
            <div style={{
              background: 'white', borderRadius: 10, padding: '8px 14px',
              display: 'flex', alignItems: 'center', gap: 8,
              border: '1.5px solid #EBEBEB',
              flexWrap: 'wrap',
            }}>
              <span style={{ fontSize: 12, color: '#888', fontFamily: 'Poppins, sans-serif' }}>Élément sélectionné :</span>

              {/* Taille via +/- */}
              <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
                <button onClick={() => updateElement(selectedId, { size: Math.max(10, (selectedEl.size || 20) - 4) })} style={{ width: 26, height: 26, borderRadius: 6, border: '1px solid #EBEBEB', background: 'white', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><ZoomOut size={12} /></button>
                <span style={{ fontSize: 12, fontWeight: 700, minWidth: 28, textAlign: 'center', fontFamily: 'Poppins, sans-serif' }}>{selectedEl.size || 20}</span>
                <button onClick={() => updateElement(selectedId, { size: Math.min(200, (selectedEl.size || 20) + 4) })} style={{ width: 26, height: 26, borderRadius: 6, border: '1px solid #EBEBEB', background: 'white', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><ZoomIn size={12} /></button>
              </div>

              {/* Rotation */}
              <button onClick={() => updateElement(selectedId, { rotation: ((selectedEl.rotation || 0) + 15) % 360 })} style={{ width: 26, height: 26, borderRadius: 6, border: '1px solid #EBEBEB', background: 'white', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }} title="Rotation"><RotateCw size={12} /></button>

              {/* Flip */}
              <button onClick={() => updateElement(selectedId, { flipX: !selectedEl.flipX })} style={{ width: 26, height: 26, borderRadius: 6, border: '1px solid #EBEBEB', background: 'white', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }} title="Miroir horizontal"><FlipHorizontal size={12} /></button>

              {/* Z-index */}
              <button onClick={() => updateElement(selectedId, { zIndex: (selectedEl.zIndex || 2) + 1 })} style={{ width: 26, height: 26, borderRadius: 6, border: '1px solid #EBEBEB', background: 'white', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }} title="Avancer"><MoveUp size={12} /></button>
              <button onClick={() => updateElement(selectedId, { zIndex: Math.max(1, (selectedEl.zIndex || 2) - 1) })} style={{ width: 26, height: 26, borderRadius: 6, border: '1px solid #EBEBEB', background: 'white', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }} title="Reculer"><MoveDown size={12} /></button>

              {/* Dupliquer */}
              <button onClick={() => duplicateElement(selectedId)} style={{ width: 26, height: 26, borderRadius: 6, border: '1px solid #EBEBEB', background: 'white', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }} title="Dupliquer"><Copy size={12} /></button>

              {/* Supprimer */}
              <button onClick={() => deleteElement(selectedId)} style={{ width: 26, height: 26, borderRadius: 6, border: '1px solid #fecaca', background: '#fff5f5', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }} title="Supprimer"><Trash2 size={12} color="#ef4444" /></button>
            </div>
          )}

          {/* Zone de preview */}
          <div style={{
            flex: 1, borderRadius: 20, overflow: 'hidden',
            boxShadow: '0 4px 40px rgba(0,0,0,0.1)',
            background: view3D ? '#0D0D0D' : 'white',
            minHeight: 540,
            position: 'relative',
          }}>
            {view3D ? (
              <Viewer3D productColor={productColor} canvasTexture={null} />
            ) : (
              <DesignCanvas
                elements={elements}
                selectedId={selectedId}
                onSelect={setSelectedId}
                onUpdate={updateElement}
                productImg={PRODUCT_IMGS[selectedProduct.id]}
                productColor={productColor}
              />
            )}

            {/* Indicateur vue */}
            <div style={{
              position: 'absolute', bottom: 14, left: '50%', transform: 'translateX(-50%)',
              background: 'rgba(0,0,0,0.6)', color: 'white',
              padding: '5px 14px', borderRadius: 20, fontSize: 11, fontWeight: 600,
              fontFamily: 'Poppins, sans-serif', pointerEvents: 'none',
            }}>
              {view3D ? 'Glissez pour pivoter · Vue 3D' : 'Glissez les éléments pour les repositionner'}
            </div>
          </div>
        </div>

        {/* ════════ PANNEAU DROIT ════════ */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>

          <button
            onClick={() => setRightOpen(v => !v)}
            style={{ alignSelf: 'flex-start', background: 'white', border: '1px solid #EBEBEB', borderRadius: 8, padding: '6px 8px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 4, fontSize: 11, color: '#666', fontFamily: 'Poppins, sans-serif' }}
          >
            {rightOpen ? <><ChevronDown size={12} /> Réduire</> : <ChevronRight size={12} />}
          </button>

          {rightOpen && <>
            {/* Couleur produit */}
            <div style={panel}>
              {sectionTitle('Couleur du produit', <ImageIcon size={14} color="#017BFE" />)}
              <div style={{ padding: 14, display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                {PRODUCT_COLORS.map(c => (
                  <button
                    key={c}
                    onClick={() => setProductColor(c)}
                    title={c}
                    style={{
                      width: 32, height: 32, borderRadius: '50%',
                      background: c,
                      border: productColor === c ? '3px solid #017BFE' : '2px solid #EBEBEB',
                      cursor: 'pointer', padding: 0,
                      transform: productColor === c ? 'scale(1.2)' : 'scale(1)',
                      transition: 'transform 0.15s, border 0.15s',
                      boxShadow: c === '#FFFFFF' ? 'inset 0 0 0 1px #ccc' : 'none',
                    }}
                  />
                ))}
              </div>
            </div>

            {/* Taille */}
            <div style={panel}>
              {sectionTitle('Taille', <Type size={14} color="#017BFE" />)}
              <div style={{ padding: 14, display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 7 }}>
                {SIZES.map(s => (
                  <button
                    key={s}
                    onClick={() => setSelectedSize(s)}
                    style={{
                      border: `1.5px solid ${selectedSize === s ? '#017BFE' : '#EBEBEB'}`,
                      borderRadius: 8, padding: '8px 4px',
                      background: selectedSize === s ? 'rgba(1,123,254,0.07)' : 'white',
                      color: selectedSize === s ? '#017BFE' : '#555',
                      fontWeight: 700, fontSize: 13, cursor: 'pointer',
                      transition: 'all 0.2s',
                      fontFamily: 'Poppins, sans-serif',
                    }}
                  >
                    {s}
                  </button>
                ))}
              </div>
            </div>

            {/* Calques */}
            {elements.length > 0 && (
              <div style={panel}>
                {sectionTitle(`Calques (${elements.length})`, <Layers size={14} color="#017BFE" />)}
                <div style={{ padding: '8px 12px', display: 'flex', flexDirection: 'column', gap: 4 }}>
                  {[...elements].reverse().map((el, i) => (
                    <div
                      key={el.id}
                      onClick={() => setSelectedId(el.id)}
                      style={{
                        display: 'flex', alignItems: 'center', gap: 8,
                        padding: '7px 10px', borderRadius: 8,
                        background: selectedId === el.id ? 'rgba(1,123,254,0.06)' : 'transparent',
                        border: `1px solid ${selectedId === el.id ? 'rgba(1,123,254,0.2)' : 'transparent'}`,
                        cursor: 'pointer', transition: 'all 0.15s',
                      }}
                    >
                      <span style={{ fontSize: 16 }}>
                        {el.type === 'text' ? '𝗧' : el.type === 'sticker' ? el.emoji : '🖼'}
                      </span>
                      <span style={{ fontSize: 12, flex: 1, color: '#444', fontFamily: 'Poppins, sans-serif', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                        {el.type === 'text' ? el.text : el.type === 'sticker' ? 'Sticker' : 'Image'}
                      </span>
                      <button
                        onClick={e => { e.stopPropagation(); deleteElement(el.id); }}
                        style={{ background: 'none', border: 'none', cursor: 'pointer', padding: 2, display: 'flex' }}
                      >
                        <Trash2 size={12} color="#ccc" />
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Récap prix */}
            <div style={{
              ...panel,
              background: 'linear-gradient(135deg, #017BFE, #00C2FF)',
              border: 'none',
            }}>
              <div style={{ padding: 20, color: 'white', textAlign: 'center' }}>
                <p style={{ fontSize: 12, opacity: 0.8, marginBottom: 4, fontFamily: 'Poppins, sans-serif' }}>Prix estimé</p>
                <p style={{ fontSize: 30, fontWeight: 900, marginBottom: 2, fontFamily: 'Poppins, sans-serif' }}>
                  {selectedProduct.price.toLocaleString('fr-FR')}
                </p>
                <p style={{ fontSize: 12, opacity: 0.8, marginBottom: 16, fontFamily: 'Poppins, sans-serif' }}>FCFA · Livraison incluse</p>
                <button
                  onClick={handleAddToCart}
                  style={{
                    width: '100%', padding: '11px',
                    background: 'white', color: '#017BFE',
                    border: 'none', borderRadius: 10,
                    fontWeight: 800, fontSize: 14, cursor: 'pointer',
                    display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8,
                    fontFamily: 'Poppins, sans-serif',
                    transition: 'opacity 0.2s',
                  }}
                  onMouseEnter={e => e.currentTarget.style.opacity = '0.9'}
                  onMouseLeave={e => e.currentTarget.style.opacity = '1'}
                >
                  {added ? <><Check size={15} /> Ajouté !</> : <><ShoppingCart size={15} /> Commander</>}
                </button>
              </div>
            </div>

            {/* Conseils */}
            <div style={{ ...panel, background: '#FAFBFF' }}>
              {sectionTitle('Conseils', <Sparkles size={14} color="#017BFE" />)}
              <ul style={{ padding: '10px 16px 14px', listStyle: 'none', display: 'flex', flexDirection: 'column', gap: 8 }}>
                {[
                  'Utilisez des PNG avec fond transparent',
                  'Résolution min. recommandée : 300 DPI',
                  'La zone pointillée = zone d\'impression',
                  'Passez en Vue 3D pour un aperçu réaliste',
                ].map((tip, i) => (
                  <li key={i} style={{ display: 'flex', alignItems: 'flex-start', gap: 8, fontSize: 12, color: '#555', lineHeight: 1.6, fontFamily: 'Poppins, sans-serif' }}>
                    <span style={{ color: '#017BFE', fontWeight: 800, flexShrink: 0 }}>·</span>
                    {tip}
                  </li>
                ))}
              </ul>
            </div>
          </>}
        </div>
      </div>
    </div>
  );
}
